// $execution shape on the error trigger carries the failed workflow + node
// + error message. Format as a compact Slack block-kit payload.
const err  = items[0]?.json?.execution?.error ?? items[0]?.json?.error ?? {};
const wf   = items[0]?.json?.workflow ?? {};
const node = err.node?.name ?? err.lastNodeExecuted ?? 'unknown';
const msg  = err.message ?? String(err);
const execUrl = items[0]?.json?.execution?.url ?? null;
const text = `:rotating_light: *SWFL n8n flow failed*\n• Workflow: \`${wf.name ?? wf.id ?? 'unknown'}\`\n• Failing node: \`${node}\`\n• Error: ${msg}` + (execUrl ? `\n• Execution: ${execUrl}` : '');
return [{ json: { text } }];
